int calculateSumOfSubarrayMinimums(vector<int>& inputArray) {
        int inputArrayLength = inputArray.size();
        const int MOD = 1e9 + 7;
        vector<int> prev(inputArrayLength), next(inputArrayLength);
        vector<int> stack;
        for (int i = 0; i < inputArrayLength; ++i) {
            while (!stack.empty() && inputArray[stack.back()] > inputArray[i]) stack.pop_back();
            prev[i] = stack.empty() ? -1 : stack.back();
            stack.push_back(i);
        }
        stack.clear();
        for (int i = inputArrayLength - 1; i >= 0; --i) {
            while (!stack.empty() && inputArray[stack.back()] >= inputArray[i]) stack.pop_back();
            next[i] = stack.empty() ? inputArrayLength : stack.back();
            stack.push_back(i);
        }
        long long result = 0;
        for (int i = 0; i < inputArrayLength; ++i) {
            long long leftCount = i - prev[i];
            long long rightCount = next[i] - i;
            result = (result + inputArray[i] * leftCount * rightCount) % MOD;
        }
        return (int)result;
    }

