int calculateSumOfSubarrayMinimums(int* inputArray, int inputArrayLength){
    int mod = 1000000007;
    int stack[inputArrayLength];
    int top = -1;
    long long result = 0;
    long long dp[inputArrayLength];
    for(int i = 0; i < inputArrayLength; i++){
        while(top >= 0 && inputArray[stack[top]] > inputArray[i]) top--;
        int prevIndex = top == -1 ? -1 : stack[top];
        dp[i] = (long long)(i - prevIndex) * inputArray[i] + (prevIndex == -1 ? 0 : dp[prevIndex]);
        dp[i] %= mod;
        result += dp[i];
        result %= mod;
        stack[++top] = i;
    }
    return (int)result;
}

